import React, { useContext, useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const Dashboard = () => {
  const { token, user, logout } = useContext(AuthContext);
  const [workouts, setWorkouts] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchWorkouts = async () => {
      try {
        const res = await fetch(`${API_URL}/api/workouts`, {
          headers: { 'x-auth-token': token },
        });
        const data = await res.json();
        if (res.ok) setWorkouts(data);
      } catch (err) {
        console.error(err);
      }
    };
    if (token) fetchWorkouts();
  }, [token]);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this workout?')) return;
    try {
      const res = await fetch(`${API_URL}/api/workouts/${id}`, {
        method: 'DELETE',
        headers: { 'x-auth-token': token },
      });
      if (res.ok) {
        setWorkouts(workouts.filter((w) => w._id !== id));
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Prepare data for chart (example: total weight lifted per session)
  const chartData = workouts.map((w) => ({
    date: new Date(w.date).toLocaleDateString(),
    totalWeight: w.sets.reduce((acc, s) => acc + s.weight * s.reps, 0),
  })).reverse();

  const totalWorkouts = workouts.length;
  const totalVolume = workouts.reduce((acc, w) => acc + w.sets.reduce((setAcc, s) => setAcc + s.weight * s.reps, 0), 0);
  const activeDays = new Set(workouts.map(w => new Date(w.date).toLocaleDateString())).size;

  return (
    <div>
      <nav className="nav">
        <h1>{user ? `${user.username}'s Fitness` : 'Fitness Tracker'}</h1>
        <div style={{display: 'flex', alignItems: 'center'}}>
          {user && <span className="nav-greeting" style={{marginRight: '20px', fontWeight: 500}}>Hello, {user.username}</span>}
          <Link to="/add"><button style={{marginRight: '10px'}}>+ New Workout</button></Link>
          <button className="secondary" onClick={logout}>Sign Out</button>
        </div>
      </nav>

      <div className="hero-section">
        <h1 style={{marginTop: '40px', marginBottom: '10px'}}>Ready to crush it today?</h1>
        <p style={{color: 'var(--apple-text-secondary)', fontSize: '18px', marginBottom: '40px'}}>Here is a summary of your progress so far.</p>
      </div>

      <div className="stats-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '40px' }}>
        <div className="stat-card">
          <h3>Total Workouts</h3>
          <p className="stat-value">{totalWorkouts}</p>
        </div>
        <div className="stat-card">
          <h3>Volume (kg)</h3>
          <p className="stat-value">{totalVolume.toLocaleString()}</p>
        </div>
        <div className="stat-card">
          <h3>Active Days</h3>
          <p className="stat-value">{activeDays}</p>
        </div>
      </div>

      {workouts.length > 0 && (
        <div className="chart-container" style={{ height: 400, marginBottom: 40 }}>
          <h3>Volume Trend</h3>
          <ResponsiveContainer width="100%" height="80%">
            <LineChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
              <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: 'var(--apple-text-secondary)'}} dy={10} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: 'var(--apple-text-secondary)'}} dx={-10} />
              <Tooltip 
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: 'var(--apple-shadow)' }}
                cursor={{ stroke: 'rgba(0,113,227,0.1)', strokeWidth: 2 }}
              />
              <Line type="monotone" dataKey="totalWeight" stroke="var(--apple-blue)" strokeWidth={3} dot={{r: 4, fill: 'var(--apple-blue)'}} activeDot={{r: 6}} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}

      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px'}}>
        <h2 style={{margin: 0}}>Recent Activity</h2>
      </div>

      {workouts.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">🏋️</div>
          <h3>Your journey starts here</h3>
          <p>You haven't logged any workouts yet. Record your first session to start tracking your progress.</p>
          <Link to="/add"><button style={{marginTop: '20px'}}>Start Your First Workout</button></Link>
        </div>
      ) : (
        <div className="workouts-grid">
          {workouts.map((w) => (
            <div key={w._id} className="workout-item">
              <h4>{new Date(w.date).toLocaleDateString()} - {w.exercise}</h4>
              <ul>
                {w.sets.map((s, i) => (
                  <li key={i}>{s.weight}kg x {s.reps}</li>
                ))}
              </ul>
              {w.notes && <p>Notes: {w.notes}</p>}
              <button className="secondary" onClick={() => handleDelete(w._id)}>Delete</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
